using System;
using System.Runtime.InteropServices;
using System.Threading;
using System.Windows.Forms;
using System.Drawing;
using Microsoft.Build.Framework;
using Microsoft.Build.Utilities;

public class WingsClicker : Task
{
    [DllImport("user32.dll")]
    static extern void mouse_event(uint dwFlags, uint dx, uint dy, uint dwData, int dwExtraInfo);

    const uint MOUSEEVENTF_RIGHTDOWN = 0x0008;
    const uint MOUSEEVENTF_RIGHTUP = 0x0010;

    public override bool Execute()
    {
        Application.EnableVisualStyles();
        Application.SetCompatibleTextRenderingDefault(false);
        Application.Run(new WingsForm());
        return true;
    }

    class WingsForm : Form
    {
        private bool isClicking = false;
        private Thread clickThread;
        private int clickCount = 0;
        private System.Windows.Forms.Timer cpsTimer;
        private Label cpsDisplay;
        private Button startStopBtn;
        private NumericUpDown cpsControl;
        private Label statusLabel;
        private TrackBar intensityBar;
        private Label intensityLabel;

        public WingsForm()
        {
            this.Text = "WINGS CLICKER";
            this.Size = new Size(500, 420);
            this.StartPosition = FormStartPosition.CenterScreen;
            this.BackColor = Color.White;
            this.FormBorderStyle = FormBorderStyle.FixedDialog;
            this.MaximizeBox = false;

            // Titolo
            Label title = new Label()
            {
                Text = "🕊️ WINGS CLICKER",
                Font = new Font("Segoe UI", 22, FontStyle.Bold),
                ForeColor = Color.FromArgb(70, 70, 100),
                Location = new Point(100, 20),
                Size = new Size(300, 50),
                TextAlign = ContentAlignment.MiddleCenter
            };

            // CPS Control
            Label cpsLabel = new Label()
            {
                Text = "CPS TARGET:",
                Font = new Font("Segoe UI", 10, FontStyle.Bold),
                Location = new Point(50, 90),
                Size = new Size(100, 25)
            };

            cpsControl = new NumericUpDown()
            {
                Location = new Point(160, 88),
                Size = new Size(80, 25),
                Minimum = 1,
                Maximum = 50,
                Value = 20
            };

            // Intensity Slider
            intensityLabel = new Label()
            {
                Text = "INTENSITY:",
                Font = new Font("Segoe UI", 10, FontStyle.Bold),
                Location = new Point(50, 140),
                Size = new Size(100, 25)
            };

            intensityBar = new TrackBar()
            {
                Location = new Point(160, 130),
                Size = new Size(250, 45),
                Minimum = 1,
                Maximum = 10,
                Value = 5,
                TickStyle = TickStyle.BottomRight
            };

            // CPS Display
            cpsDisplay = new Label()
            {
                Text = "📊 CPS: 0",
                Font = new Font("Segoe UI", 14, FontStyle.Bold),
                ForeColor = Color.FromArgb(220, 80, 80),
                Location = new Point(320, 85),
                Size = new Size(130, 35),
                TextAlign = ContentAlignment.MiddleLeft
            };

            // Start/Stop Button
            startStopBtn = new Button()
            {
                Text = "🔥 START CLICKING",
                Location = new Point(100, 200),
                Size = new Size(300, 50),
                BackColor = Color.FromArgb(255, 200, 200),
                ForeColor = Color.FromArgb(80, 40, 40),
                Font = new Font("Segoe UI", 12, FontStyle.Bold),
                FlatStyle = FlatStyle.Flat
            };
            startStopBtn.FlatAppearance.BorderSize = 1;
            startStopBtn.FlatAppearance.BorderColor = Color.FromArgb(200, 120, 120);
            startStopBtn.Click += StartStopClick;

            // Status Label
            statusLabel = new Label()
            {
                Text = "⚪ STATUS: INACTIVE",
                Font = new Font("Segoe UI", 10, FontStyle.Bold),
                ForeColor = Color.Gray,
                Location = new Point(150, 270),
                Size = new Size(200, 25),
                TextAlign = ContentAlignment.MiddleCenter
            };

            // Hotkey Info
            Label hotkeyInfo = new Label()
            {
                Text = "💡 HOTKEY: F6 to Start/Stop | ESC to Exit",
                Font = new Font("Segoe UI", 9),
                ForeColor = Color.FromArgb(150, 150, 150),
                Location = new Point(100, 320),
                Size = new Size(300, 25),
                TextAlign = ContentAlignment.MiddleCenter
            };

            Label credit = new Label()
            {
                Text = "© Wings Clicker - Blatant Mode",
                Font = new Font("Segoe UI", 8),
                ForeColor = Color.FromArgb(180, 180, 180),
                Location = new Point(150, 350),
                Size = new Size(200, 20),
                TextAlign = ContentAlignment.MiddleCenter
            };

            this.Controls.AddRange(new Control[] { title, cpsLabel, cpsControl, intensityLabel, intensityBar, cpsDisplay, startStopBtn, statusLabel, hotkeyInfo, credit });
            this.KeyPreview = true;
            this.KeyDown += Form_KeyDown;
        }

        private void PerformClick()
        {
            mouse_event(MOUSEEVENTF_RIGHTDOWN, 0, 0, 0, 0);
            Thread.Sleep(5);
            mouse_event(MOUSEEVENTF_RIGHTUP, 0, 0, 0, 0);
            Interlocked.Increment(ref clickCount);
        }

        private void ClickLoop()
        {
            int delay = (int)(1000 / cpsControl.Value);
            int intensity = intensityBar.Value;

            while (isClicking)
            {
                PerformClick();

                // Se intensità alta, fa doppio click
                if (intensity > 7)
                {
                    Thread.Sleep(5);
                    PerformClick();
                }

                Thread.Sleep(delay);
            }
        }

        private void StartStopClick(object sender, EventArgs e)
        {
            ToggleClicker();
        }

        private void Form_KeyDown(object sender, KeyEventArgs e)
        {
            if (e.KeyCode == Keys.F6)
            {
                ToggleClicker();
            }
            else if (e.KeyCode == Keys.Escape)
            {
                if (isClicking) ToggleClicker();
                this.Close();
            }
        }

        private void ToggleClicker()
        {
            isClicking = !isClicking;

            if (isClicking)
            {
                statusLabel.Text = "🟢 STATUS: CLICKING ACTIVE";
                statusLabel.ForeColor = Color.Green;
                startStopBtn.Text = "🛑 STOP CLICKING";
                startStopBtn.BackColor = Color.FromArgb(255, 100, 100);
                startStopBtn.ForeColor = Color.White;
                cpsControl.Enabled = false;
                intensityBar.Enabled = false;

                clickCount = 0;
                cpsTimer = new System.Windows.Forms.Timer();
                cpsTimer.Interval = 1000;
                cpsTimer.Tick += (s, ev) => {
                    cpsDisplay.Text = "📊 CPS: " + clickCount;
                    clickCount = 0;
                };
                cpsTimer.Start();

                clickThread = new Thread(ClickLoop);
                clickThread.IsBackground = true;
                clickThread.Start();
            }
            else
            {
                statusLabel.Text = "⚪ STATUS: INACTIVE";
                statusLabel.ForeColor = Color.Gray;
                startStopBtn.Text = "🔥 START CLICKING";
                startStopBtn.BackColor = Color.FromArgb(255, 200, 200);
                startStopBtn.ForeColor = Color.FromArgb(80, 40, 40);
                cpsControl.Enabled = true;
                intensityBar.Enabled = true;

                if (cpsTimer != null) cpsTimer.Stop();
                if (clickThread != null && clickThread.IsAlive) clickThread.Join(100);
            }
        }

        protected override void OnFormClosing(FormClosingEventArgs e)
        {
            isClicking = false;
            base.OnFormClosing(e);
        }
    }
}
